output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(SUM(?games) AS ?total_games) WHERE {
  ?series wdt:P31 wd:Q1363275 .
  {
    ?series wdt:P1133 wd:Q334634 ; wdt:P1134 wd:Q650840 .
    ?series wdt:P11281 ?games .
  } UNION {
    ?series wdt:P1133 wd:Q650840 ; wdt:P1134 wd:Q334634 .
    ?series wdt:P11281 ?games .
  }
}

